"""44 claim cases matching the frontend mocks."""


def _img(id_, n=3):
    return [f"https://picsum.photos/seed/claim-{id_}-{i+1}/400/280" for i in range(n)]


def _claim(id_, obj, conv, esm, esm_reason, flags, issue, part, status, justification, support, valid, severity):
    return {
        "id": id_, "user_id": f"user_{id_:03d}", "object": obj,
        "conversation": conv, "image_urls": _img(id_),
        "evidence_standard_met": esm, "evidence_standard_met_reason": esm_reason,
        "risk_flags": flags, "issue_type": issue, "object_part": part,
        "claim_status": status, "claim_status_justification": justification,
        "supporting_image_ids": support, "valid_image": valid, "severity": severity,
    }


